import React from 'react';
import { Link, useNavigate } from 'react-router-dom';

function Navbar() {
    const navigate = useNavigate();
    const user = JSON.parse(localStorage.getItem('user') || '{}');

    const handleLogout = () => {
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        navigate('/login');
    };

    return (
        <nav style={{
            display: 'flex',
            justifyContent: 'space-between',
            padding: '10px 20px',
            backgroundColor: '#2c3e50',
            color: 'white'
        }}>
            <div style={{ display: 'flex', gap: '20px' }}>
                <Link to="/dashboard" style={{ color: 'white', textDecoration: 'none' }}>Dashboard</Link>
                <Link to="/tasks" style={{ color: 'white', textDecoration: 'none' }}>Tasks</Link>
                <Link to="/tasks/new" style={{ color: 'white', textDecoration: 'none' }}>New Task</Link>
                <Link to="/audit-log" style={{ color: 'white', textDecoration: 'none' }}>Activity Log</Link>
            </div>
            <div style={{ display: 'flex', gap: '15px', alignItems: 'center' }}>
                <span>{user.email} ({user.role})</span>
                <button 
                    onClick={handleLogout}
                    style={{
                        padding: '5px 15px',
                        backgroundColor: '#e74c3c',
                        color: 'white',
                        border: 'none',
                        borderRadius: '4px',
                        cursor: 'pointer'
                    }}
                >
                    Logout
                </button>
            </div>
        </nav>
    );
}

export default Navbar;
